// FIXED: Using confirmed working Gemini model
const GEMINI_API_KEY = 'AIzaSyCu7cMyJAB4ossEePGYQQGpzjlqAfbIG2E';

const ctx = String($input.first().json.conversation_context || '').trim();

// Handle empty context
if (!ctx) {
  console.log('⚠️ No conversation context provided, returning default values');
  return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], api_used: 'default' } }];
}

const prompt = `You are a personality detector. Infer Big Five from the user text for THIS TURN ONLY. Return JSON ONLY exactly as: {"ocean_disc":{"O":-1|0|1,"C":-1|0|1,"E":-1|0|1,"A":-1|0|1,"N":-1|0|1}} No prose.\n\nText: ${ctx}`;

console.log('🚀 Calling Gemini API for OCEAN detection...');
console.log('📝 Prompt length:', prompt.length, 'characters');
console.log('🔗 Context:', ctx.substring(0, 100) + (ctx.length > 100 ? '...' : ''));

// ✅ CONFIRMED WORKING MODEL: gemini-1.5-flash
const model = 'gemini-1.5-flash';
const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${GEMINI_API_KEY}`;

console.log('🌐 API URL:', apiUrl);
console.log('🤖 Model:', model);

const options = {
  method: 'POST',
  url: apiUrl,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { 
      temperature: 0.1, 
      maxOutputTokens: 200, 
      topK: 40, 
      topP: 0.95 
    },
    safetySettings: [
      { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' },
      { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_MEDIUM_AND_ABOVE' }
    ]
  }),
  timeout: 20000
};

try {
  console.log('📡 Making HTTP request...');
  const response = await this.helpers.httpRequest(options);

  console.log('📊 Raw Gemini Response:', JSON.stringify(response, null, 2));
  console.log('✅ HTTP request successful');

  if (response.candidates && response.candidates.length > 0) {
    let content = response.candidates[0].content.parts[0].text;
    console.log('✅ Got candidates from API');
    console.log('📝 Raw content received:', content);

    // Handle JSON extraction (strip markdown if present)
    let cleanedContent = content;
    if (content.includes('```')) {
      cleanedContent = content.replace(/```json\s*|\s*```/g, '').trim();
      console.log('🧹 Cleaned content:', cleanedContent);
    }

    // Validate JSON
    try {
      const testParse = JSON.parse(cleanedContent);
      console.log('✅ JSON parsing successful:', JSON.stringify(testParse));

      return [{ json: { choices: [{ message: { content: cleanedContent } }], api_used: model, status: 'success' } }];
    } catch (jsonError) {
      console.log('⚠️ JSON parsing failed:', jsonError.message);
      console.log('🔄 Using original content as fallback');

      return [{ json: { choices: [{ message: { content: content } }], api_used: model, status: 'json_parse_failed' } }];
    }

  } else {
    console.log('❌ No candidates in response');

    // Check for safety blocking
    if (response.promptFeedback && response.promptFeedback.blockReason) {
      const reason = response.promptFeedback.blockReason;
      console.log(`🛡️ Blocked by safety filters: ${reason}`);

      return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], error: `Safety filter: ${reason}`, api_used: 'blocked' } }];
    } else {
      console.log('🔍 Full response for debugging:', JSON.stringify(response, null, 2));

      return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], error: 'No candidates', api_used: 'no_candidates' } }];
    }
  }

} catch (error) {
  console.log('❌ HTTP Request Error:', error.message);
  console.log('📊 Error details:', error);

  // Enhanced error analysis
  if (error.message && error.message.includes('404')) {
    console.log('🔍 404 Error Analysis:');
    console.log('   • Model used:', model);
    console.log('   • URL constructed:', apiUrl);
    console.log('   • Possible issue: Model name incorrect or endpoint changed');
  } else if (error.message && error.message.includes('429')) {
    console.log('⚠️ Quota exceeded - expected on free tier');
  }

  return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], error: error.message, api_used: 'error', model_used: model, url_used: apiUrl } }];
}

// Enhanced JSON parsing with better error handling
const det = $input.first()?.json || {};
const raw = det?.choices?.[0]?.message?.content ?? '';

// Get session data
const ingestData = $items('Ingest (Per-turn, no smoothing)', 'main', 0)?.json || {};

console.log('Parse Detection - API Status:', det.status || 'unknown');
console.log('Parse Detection - API Used:', det.api_used || 'unknown');
console.log('Parse Detection - Error:', det.error || 'none');
console.log('Parse Detection - Raw content:', raw);

let parsed = {};

// Enhanced JSON extraction
if (raw) {
  let jsonContent = raw;

  // Strip markdown blocks if present
  if (raw.includes('```')) {
    jsonContent = raw.replace(/```json\s*|\s*```/g, '').trim();
    console.log('🧹 Stripped markdown:', jsonContent);
  }

  try {
    parsed = JSON.parse(jsonContent);
    console.log('✅ JSON parsing successful');
  } catch (e1) {
    console.log('⚠️ Direct parsing failed, trying regex extraction...');

    const jsonMatch = raw.match(/\{[^}]*"ocean_disc"[^}]*\{[^}]*\}[^}]*\}/);
    if (jsonMatch) {
      try {
        parsed = JSON.parse(jsonMatch[0]);
        console.log('✅ Regex extraction successful');
      } catch (e2) {
        console.log('❌ Regex extraction failed:', e2.message);
      }
    }
  }
}

console.log('Parse Detection - Parsed object:', JSON.stringify(parsed));

// Extract OCEAN values
let oceanDisc = parsed?.ocean_disc || { O: 0, C: 0, E: 0, A: 0, N: 0 };

// Session data
const turnText = ingestData?.clean_msg || '';
const sessionId = ingestData?.session_id || '';

console.log('Parse Detection - Final OCEAN values:', JSON.stringify(oceanDisc));
console.log('Parse Detection - Session ID:', sessionId);
console.log('Parse Detection - Turn text:', turnText);

return [{
  json: {
    ocean_disc: oceanDisc,
    turn_text: turnText,
    session_id: sessionId,
    detection_status: det.status || 'unknown',
    api_used: det.api_used || 'unknown'
  }
}];

