// Response generation with confirmed working model
const GEMINI_API_KEY = 'AIzaSyCu7cMyJAB4ossEePGYQQGpzjlqAfbIG2E';

const inputData = $input.first()?.json || {};
const directives = inputData?.directives || [];
const sessionId = inputData?.session_id || '';
const turnText = inputData?.turn_text || '';
const oceanDisc = inputData?.ocean_disc || { O:0, C:0, E:0, A:0, N:0 };

console.log('Generate Response - Detection status:', inputData.detection_status);
console.log('Generate Response - Directives:', JSON.stringify(directives));

let userText = turnText.trim();
if (!userText) {
  userText = 'Please provide a supportive reply.';
}

const systemPrompt = [
  'You are a supportive assistant. Follow these behavior directives strictly:',
  JSON.stringify(directives),
  'Constraints: stay grounded in the user text only; 1-2 questions max; 70-150 words.'
].join(' ');

const fullPrompt = `${systemPrompt}\n\nUser: ${userText}`;

console.log('🚀 Calling Gemini API for response generation...');

// ✅ CONFIRMED WORKING MODEL
const model = 'gemini-1.5-flash';
const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${GEMINI_API_KEY}`;

const options = {
  method: 'POST',
  url: apiUrl,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    contents: [{ parts: [{ text: fullPrompt }] }],
    generationConfig: { 
      temperature: 0.7, 
      maxOutputTokens: 220, 
      topK: 40, 
      topP: 0.95 
    }
  }),
  timeout: 20000
};

try {
  const response = await this.helpers.httpRequest(options);

  if (response.candidates && response.candidates.length > 0) {
    const content = response.candidates[0].content.parts[0].text;
    console.log('✅ Response generation successful');
    console.log('📝 Generated:', content.substring(0, 100) + '...');

    return {
      json: {
        choices: [{ message: { content } }],
        session_id: sessionId,
        turn_text: turnText,
        ocean_disc: oceanDisc,
        directives: directives,
        api_used: model,
        status: 'success'
      }
    };
  } else {
    console.log('❌ No candidates in response generation');

    return {
      json: {
        choices: [{ message: { content: 'Response generation temporarily unavailable. Take 3 deep breaths.' } }],
        error: 'No candidates',
        session_id: sessionId,
        turn_text: turnText,
        ocean_disc: oceanDisc,
        directives: directives,
        api_used: 'no_candidates'
      }
    };
  }

} catch (error) {
  console.log('❌ Response generation error:', error.message);

  return {
    json: {
      choices: [{ message: { content: 'Response generation encountered an error. Take 3 deep breaths.' } }],
      error: error.message,
      session_id: sessionId,
      turn_text: turnText,
      ocean_disc: oceanDisc,
      directives: directives,
      api_used: 'error'
    }
  };
}

